/**
 * AccountTrigger — the only trigger on Account.
 * All event routing lives in AccountTriggerHandler.
 */
trigger AccountTrigger on Account (
    before insert, before update, before delete,
    after insert, after update, after delete, after undelete
) {
    new AccountTriggerHandler().run();
}

public with sharing class AccountTriggerHandler extends TriggerHandler {

    public AccountTriggerHandler() {
        super('AccountTriggerHandler');
    }

    // ---- folded from AccountBeforeInsert.trigger (verbatim logic) ----
    public override void beforeInsert() {
        for (Account a : (List<Account>) Trigger.new) {
            if (String.isBlank(a.Name)) {
                a.addError('Name is required');
            }
            if (a.Industry == null) {
                a.Industry = 'Other';
            }
        }
    }

    // ---- folded from AccountAfterInsert.trigger (verbatim logic) ----
    public override void afterInsert() {
        List<Task> welcomeTasks = new List<Task>();
        for (Account a : (List<Account>) Trigger.new) {
            welcomeTasks.add(new Task(
                Subject = 'Welcome ' + a.Name,
                WhatId = a.Id
            ));
        }
        if (!welcomeTasks.isEmpty()) {
            insert welcomeTasks;
        }
    }

    // ---- folded from AccountAfterUpdate.trigger (verbatim call site) ----
    public override void afterUpdate() {
        AccountAfterUpdateService.syncToWarehouse(
            (Map<Id, Account>) Trigger.newMap,
            (Map<Id, Account>) Trigger.oldMap
        );
    }
}
